var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"전 딱히 제 삶을 불행하다고 생각한 적이 없습니다.","JPN":"私は、自分が不幸だと考えたことはありません。","ENG":"I've never felt sorry for myself.","TWN":"我從來沒有覺得我的人生很不幸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"본체가 어떤 사람인진 기억 속에 들어있지만, 그쪽도 어지간히 불우한 과거를 갖고 있거든요.","JPN":"オリジナルがどんな人間かは記憶にありますが、彼は彼で、それなりに不遇な過去を持っていましたからね。","ENG":"I know who my original was from the memories I've got. He was a poor wretch.","TWN":"我記得本體是什麼樣的人，但他卻有很多不幸的過去。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"오히려 관리국 병사들 중 하나로 살아가는 지금이 훨씬 행복하고, 보람차다고 할 수 있죠.","JPN":"むしろ管理局の兵士の一人として生きている今の方が、ずっと幸福で、やりがいのある日々を過ごせています。","ENG":"I'm not. I'm happy being a soldier for the Administration. It's rewarding.","TWN":"反而是作為管理局士兵的一員，現在過得更加幸福，更有意義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 고개를 들어보면 저보다 부러운 삶을 살고 있는 이들이 수도 없이 많겠지만.","JPN":"まあ、周りに目を向ければ、羨ましい生き方をしている人間はいくらでもいるだろうと思います。","ENG":"Well, I'm sure a lot of people out there are living much happier lives than I am.","TWN":"不過想想，或許有很多人過著比我更令人羨慕的生活。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"굳이 그렇게 닿지 않을 이상에 손만 뻗고 있을 필요는 없지 않습니까?","JPN":"しかし、わざわざ手の届かない理想を思い描き、手を伸ばしてみたところで、何になりましょう。","ENG":"But why should I be jealous of something that I can never have?","TWN":"但沒必要刻意伸出手，去追求無法觸及的事物吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"지금처럼 사장님 회사에서 계속 일하는 지금도 남부럽지 않게 퍽 괜찮은 삶입니다.","JPN":"私は、社長の会社で働くという生き方に満足しています。他人を羨む必要性は感じません。","ENG":"Besides, working at your company is as good a life as any other.","TWN":"就像現在這樣，在老闆的公司工作也算是令人羨慕的生活了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"흔히 가족 같은 회사라고들 하죠.","JPN":"俗に、家族のような会社だとも言うではありませんか。","ENG":"A company that's like a family, as they say.","TWN":"老闆常說公司就像家一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"......무슨 생각하고 계신지 압니다. 하지만 제게는 정말 이 회사 사람들만한 존재가 없습니다.","JPN":"……何をお考えなのかはおおよそ察しがつきます。しかし確かに、私にとってこの会社の者達は、他の何よりも大きな存在です。","ENG":"I know what you're thinking. But everyone at this company really is my family.","TWN":"......我知道您在想什麼。但是對我來說，真的沒有比這個公司的人更好的存在了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"주제넘게 들릴 지도 모르겠지만, 사장님 또한 제가 소중히 여기는 가족이거든요.","JPN":"分を弁えずに申し上げるなら、社長もまた、私にとって大切な家族の一人なんです。","ENG":"Including you.","TWN":"也許您聽起來會覺得很僭越，但老闆也是我最重要的家人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};